// Extract and validate incoming research payload
const body = $input.first().json.body ?? $input.first().json;

const required = ['practiceName', 'primaryGapType', 'marketingMaturityScore', 'likelihoodToBuyScore', 'priorityLevel', 'researchSummary'];
const missing = required.filter(f => body[f] === undefined || body[f] === null);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Gap-type → Gamma theme mapping (matches prospectResearch.ts)
const themeMap = {
  SEO:        'consultant',
  Reputation: 'serene',
  Video:      'aurora',
  Authority:  'marine',
  Maps:       'icebreaker',
};

const gapType = body.primaryGapType ?? 'SEO';
const themeId = themeMap[gapType] ?? 'consultant';

return [{
  json: {
    ...body,
    themeId,
    deckTitle: `${body.practiceName} — Market Opportunity Assessment`,
    locationStr: [body.city, body.state].filter(Boolean).join(', '),
  }
}];

// Build the Gamma deck content from research data
const d = $input.first().json;

const gapSlides = {
  SEO: {
    headline: `The SEO Gap — You're Invisible Where It Counts`,
    bullets: [
      `Competitors rank for "dental implants ${d.locationStr}" — this practice does not`,
      `Missing dedicated implant/All-on-4/full-arch landing pages`,
      `Google Maps pack visibility gap vs. primary competitor`,
      `Keyword gap growing every month without intervention`,
    ]
  },
  Reputation: {
    headline: 'The Reputation Gap — Reviews Drive Implant Decisions',
    bullets: [
      d.primaryCompetitorName && d.competitorReviewCount
        ? `${d.primaryCompetitorName}: ${d.competitorReviewCount} reviews (${d.competitorStarRating ?? 'N/A'}⭐) vs. this practice`
        : 'Primary competitor has significantly more reviews',
      'Patients comparing practices online choose the practice with more social proof',
      'Review velocity gap compounds over time — gap widens every month',
      'Reputation generation and response strategy currently absent',
    ]
  },
  Video: {
    headline: 'The Video Gap — Authority is Built on Camera',
    bullets: [
      'No doctor authority video detected on website or YouTube',
      'Competitors use patient testimonial video to pre-sell high-value cases',
      'Before/after video case documentation builds trust before the consultation',
      'Video is the #1 trust signal for $25K+ implant patients',
    ]
  },
  Authority: {
    headline: 'The Authority Gap — Patients Need to Trust Before They Spend',
    bullets: [
      'Doctor online presence and thought leadership underdeveloped',
      'Competitors actively showcasing certifications, case studies, specialist positioning',
      'Trust signals missing: before/after gallery, financing info, credentialed doctor bio',
      'Implant patients spend $25K+ — authority content converts skeptics',
    ]
  },
  Maps: {
    headline: 'The Maps Visibility Gap — The Pack is Where Patients Decide',
    bullets: [
      d.competitorMapsPosition && d.competitorMapsPosition <= 3
        ? `${d.primaryCompetitorName ?? 'Primary competitor'} holds Maps pack position #${d.competitorMapsPosition}`
        : 'Competitors dominating the local Maps pack for implant searches',
      'Citation consistency, photo count, and Q&As all affect Maps ranking',
      '90% of patients searching locally never scroll past the Maps pack',
      'Every week out of the pack = consultations going to competitors',
    ]
  }
};

const gapType = d.primaryGapType ?? 'SEO';
const slide = gapSlides[gapType] ?? gapSlides.SEO;

const competitorSection = d.primaryCompetitorName
  ? `## Slide 5: The Competitive Landscape\n**Primary Threat: ${d.primaryCompetitorName}**${d.primaryCompetitorWebsite ? ` — ${d.primaryCompetitorWebsite}` : ''}\n${d.competitorReviewCount ? `- Reviews: **${d.competitorReviewCount}** ${d.competitorStarRating ? `(${d.competitorStarRating}⭐)` : ''}` : ''}\n${d.competitorRunningAds ? '- Running Google Ads: **YES** — actively capturing patients searching now' : ''}\n${d.competitorMapsPosition && d.competitorMapsPosition <= 3 ? `- Google Maps Pack: **Position #${d.competitorMapsPosition}**` : ''}\n${d.competitorPressureScore ? `- Competitive Pressure Score: **${d.competitorPressureScore}/100**` : ''}`
  : `## Slide 5: The Competitive Landscape\nCompetitors are actively dominating local implant search — full competitive analysis available.`;

const urgencyLine = d.primaryCompetitorName && d.competitorReviewCount
  ? `If **${d.primaryCompetitorName}** continues at current velocity, the review gap will double within 12 months.`
  : `Competitors are actively investing in marketing while this practice's digital position erodes.`;

const deckContent = `# ${d.practiceName} — Market Opportunity Assessment
**Prepared by Progressive Dental Marketing | ${new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}**

## Slide 1: Title
**${d.practiceName}**${d.locationStr ? ` | ${d.locationStr}` : ''}
Market Opportunity Assessment
Prepared for Discovery Call

## Slide 2: Market Opportunity
Growing market for full-arch implant cases in ${d.locationStr || 'this market'}
Practices that own the digital presence own the patient flow
First 3 results in local search capture 75%+ of patient clicks

## Slide 3: Where You Stand Today
**Marketing Maturity Score: ${Math.round(d.marketingMaturityScore)}/100**
**Market Priority: ${d.priorityLevel}**

${d.researchSummary}

## Slide 4: ${slide.headline}
${slide.bullets.filter(Boolean).map(b => `- ${b}`).join('\n')}

${competitorSection}

## Slide 6: The Cost of Standing Still
${urgencyLine}
Every month of inaction widens the competitive gap permanently.
The practices that invest in their digital presence now will dominate this market for years.

## Slide 7: The Market Domination Strategy
Focus: **${gapType}** — the highest-leverage gap in this market
Fastest path: Close the ${gapType} gap to appear where patients are already searching
Target: High-income, high-45+ population areas in the 10-30 mile radius

## Slide 8: What Progressive Dental Marketing Delivers
- Dental implant marketing specialists — exclusive focus on dental practices
- Full team: PPC, SEO, Social Media, Video Production, Reputation Management
- Dedicated Account Manager — one point of contact, full accountability
- Data-driven — every dollar tracked, every result measured

## Slide 9: The 90-Day Roadmap
**Month 1:** Foundation — audit, strategy, and quick wins on ${gapType}
**Month 2:** Execution — content, campaigns, and visibility infrastructure live
**Month 3:** Optimization — compound momentum, first measurable patient inquiry increases

## Slide 10: Next Step
**Discovery Call — 30 Minutes to Map Your Custom Strategy**
Let's show you exactly what your competitors are doing — and how we take the lead back.
${d.priorityLevel === 'Top Priority' || d.priorityLevel === 'High' ? '⚡ High-priority market — schedule within 5 business days.' : "Strong opportunity — let's start the conversation."}`;

return [{
  json: {
    ...d,
    deckContent,
  }
}];

// Extract Gamma URL from API response
const response = $input.first().json;

// Gamma returns gammaUrl at various paths depending on API version
const gammaUrl = response.gammaUrl
  ?? response.url
  ?? response.data?.gammaUrl
  ?? response.data?.url
  ?? response.result?.gammaUrl;

if (!gammaUrl) {
  throw new Error(`Gamma did not return a URL. Full response: ${JSON.stringify(response).slice(0, 800)}`);
}

const upstream = $('Build Deck Content').first().json;

return [{
  json: {
    ...upstream,
    gammaUrl,
  }
}];
